parameters.content:
## 12. Append URL Sources List
[Read more about the Code node]({{ $env.WEBHOOK_URL }}

For our source URLs, we'll manually compose the Notion blocks for them - this is because there's usually a lot of them! We'll then append to the end of the other blocks.

parameters.jsCode:
const urls = Object.values($('JobType Router').first().json.data.all_urls
  .reduce((acc, url) => ({ ...acc, [url]: url }),{}));
const chunksize = 50;
const splits = Math.max(1, Math.floor(urls.length/chunksize));

const blocks = Array(splits).fill(0)
  .map((_, idx) => {
    const block = urls
      .slice(
        idx * chunksize, 
        (idx * chunksize) + chunksize - 1
      )
      .map(url => {
        return {
          object: "block",
          type: "bulleted_list_item",
          bulleted_list_item: {
            rich_text: [
              { type: "text", text: { content: url } }
            ]
          }
        }
      });
    return { json: { block } }
  });

return [
  { json: {
    block:[{
      "object": "block",
      "type": "heading_2",
      "heading_2": {
        "rich_text": [
          {
            "type": "text",
            "text": {
              "content": "Sources"
            }
          }
        ]
      }
    }]
  } },
  ...blocks
];

